<Stats id="monster-psychic_stalker--stats" atts={[0,18,0,13,15,23]} bab={6} cmb={10} cmd={26} cmdP="can't be tripped" feats={["Blind-Fight","Combat Reflexes","Improved Initiative",["Skill Focus"," (Perception)"]]} skills={{"fly":{"b":19},"intm":{"b":17},"per":{"b":16},"sm":{"b":13},"stl":{"b":15}}} lang={["C"]} sq="formless" />
